sql:
SELECT officer_id, COUNT(*) AS number_of_crimes_reported
FROM crime_patterns
GROUP BY officer_id;

SELECT case_status
FROM crime_patterns
WHERE case_status = 'Closed';

external_knowledge:
- The confidence score represents the reliability or accuracy of the analysis results; 
- A higher confidence score indicates a more reliable analysis; 
- The requirement of at least two analyses for each crime type ensures that the average confidence score is calculated based on multiple evaluations, providing a more accurate representation of the crime type's confidence score.

sql:
SELECT AVG(cp_score) AS average_score
FROM crime_patterns
WHERE weather_conditions = 'Cloudy';

SELECT AVG(confidence_score) AS avg_confidence
FROM crime_analysis
WHERE risk_level = 'Medium' AND geographic_area = 'East Side';
